// Scoped to .cc-cora-form. Generated by microsites/_dversion-build.mjs.
(function () {
  // Use window.document explicitly here — declaring  const document
  // = …  later in this scope hoists the binding to the top of the
  // function as TDZ, so plain  document.querySelector  on this line
  // would throw "Cannot access 'document' before initialization".
  const ROOT = window.document.querySelector('.cc-cora-form');
  if (!ROOT) return;

  // Re-bind document.* lookups to resolve against the partial root,
  // so IDs and class selectors can't collide with the host Drupal page.
  const document = new Proxy(window.document, {
    get(target, prop) {
      if (prop === 'getElementById') return (id) => ROOT.querySelector('#' + CSS.escape(id));
      if (prop === 'querySelector') return (sel) => ROOT.querySelector(sel);
      if (prop === 'querySelectorAll') return (sel) => ROOT.querySelectorAll(sel);
      const v = target[prop];
      return typeof v === 'function' ? v.bind(target) : v;
    },
  });

const CONFIG = {
  AZURE_FUNCTION_URL: '',
  // Example when deployed:
  // 'https://func-cora-cos-prod.azurewebsites.net/api/cora-submit?code=YOUR_KEY'

  CORA_EMAIL: 'City.Communications@coloradosprings.gov',
  // Primary CORA coordinator — receives mailto fallback submissions
};


// --- next script block ---


// ── CONFIG READ ──────────────────────────────────────────────────
const AZURE_URL  = CONFIG.AZURE_FUNCTION_URL || '';
const CORA_EMAIL = CONFIG.CORA_EMAIL         || 'City.Communications@coloradosprings.gov';
const USE_AZURE  = !!AZURE_URL;

// ── MODE BANNER ──────────────────────────────────────────────────
(function() {
  const banner   = document.getElementById('mode-banner');
  const modeText = document.getElementById('mode-text');
  const mailtoPanel = document.getElementById('mailto-panel');

  if (USE_AZURE) {
    banner.className = 'mode-banner mode-azure';
    modeText.textContent = 'Online submission active — your request will be processed automatically.';
    mailtoPanel.style.display = 'none';
  } else {
    banner.className = 'mode-banner mode-mailto';
    modeText.textContent = 'Email submission mode — fill in the form below and we will prepare your request for your email client.';
    mailtoPanel.style.display = 'block';
    document.getElementById('mailto-note').textContent =
      'Fill in the form below, then click the button to open your email client with everything pre-filled.';
  }
})();

// ── CHARACTER COUNT ──────────────────────────────────────────────
document.getElementById('record-description').addEventListener('input', function() {
  document.getElementById('desc-count').textContent =
    `${this.value.length.toLocaleString()} / 2,000 characters`;
});

// ── CONDITIONAL FIELDS ──────────────────────────────────────────
document.getElementById('fee-waiver-check').addEventListener('change', function() {
  const field = document.getElementById('waiver-reason-field');
  field.style.display = this.checked ? 'block' : 'none';
  if (this.checked) document.getElementById('waiver-reason').focus();
});

document.getElementById('ada-request').addEventListener('change', function() {
  const field = document.getElementById('ada-detail-field');
  field.style.display = this.checked ? 'block' : 'none';
  if (this.checked) document.getElementById('ada-detail').focus();
});

// ── VALIDATION ───────────────────────────────────────────────────
function validate() {
  const rules = [
    { id: 'record-description', fieldId: 'field-description', errId: 'desc-error',
      check: v => v.trim().length >= 10 },
    { id: 'requester-name',     fieldId: 'field-name',        errId: 'name-error',
      check: v => v.trim().length >= 2 },
    { id: 'requester-address',  fieldId: 'field-address',     errId: 'addr-error',
      check: v => v.trim().length >= 5 },
    { id: 'requester-email',    fieldId: 'field-email',       errId: 'email-error',
      check: v => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v.trim()) },
  ];
  let valid = true, firstErr = null;
  rules.forEach(r => {
    const el    = document.getElementById(r.id);
    const field = document.getElementById(r.fieldId);
    if (!r.check(el.value)) {
      field.classList.add('error');
      valid = false;
      if (!firstErr) firstErr = el;
    } else {
      field.classList.remove('error');
    }
  });
  if (firstErr) firstErr.focus();
  return valid;
}

// ── COLLECT FORM DATA ────────────────────────────────────────────
function collectData() {
  const get = id => (document.getElementById(id) || {}).value || '';
  const checked = id => (document.getElementById(id) || {}).checked || false;
  const radio = name => {
    const el = document.querySelector(`input[name="${name}"]:checked`);
    return el ? el.value : '';
  };
  return {
    'record-description': get('record-description'),
    'date-range':         get('date-range'),
    'doc-number':         get('doc-number'),
    'department':         get('department'),
    'topic-keywords':     get('topic-keywords'),
    'format':             radio('format'),
    'fee-waiver':         checked('fee-waiver-check') ? 'yes' : '',
    'waiver-reason':      get('waiver-reason'),
    'ada-request':        checked('ada-request') ? 'yes' : '',
    'ada-detail':         get('ada-detail'),
    'requester-name':     get('requester-name'),
    'requester-address':  get('requester-address'),
    'requester-email':    get('requester-email'),
    'requester-phone':    get('requester-phone'),
    'website':            get('website'), // honeypot
  };
}

// ── BUILD MAILTO BODY ────────────────────────────────────────────
function buildMailtoHref(data) {
  const dept = document.getElementById('department');
  const deptLabel = dept.options[dept.selectedIndex].text;
  const feeWaiver = data['fee-waiver'] === 'yes'
    ? `\nFEE WAIVER REQUESTED: Yes${data['waiver-reason'] ? '\nReason: ' + data['waiver-reason'] : ''}`
    : '\nFEE WAIVER REQUESTED: No';
  const ada = data['ada-request'] === 'yes'
    ? `\nADA ACCOMMODATION: Yes${data['ada-detail'] ? '\nDetail: ' + data['ada-detail'] : ''}`
    : '';

  const body = [
    'COLORADO SPRINGS CORA RECORDS REQUEST',
    '======================================',
    '',
    'RECORDS REQUESTED:',
    data['record-description'],
    '',
    'Date range: '       + (data['date-range']      || 'Not specified'),
    'Document number: '  + (data['doc-number']       || 'Not provided'),
    'Department: '       + (deptLabel                || 'Not specified'),
    'Keywords/topic: '   + (data['topic-keywords']   || 'None'),
    'Format requested: ' + (data['format']           || 'Electronic'),
    feeWaiver,
    ada,
    '',
    'REQUESTER INFORMATION:',
    'Name: '    + data['requester-name'],
    'Address: ' + data['requester-address'],
    'Email: '   + data['requester-email'],
    'Phone: '   + (data['requester-phone'] || 'Not provided'),
    '',
    '======================================',
    'Submitted via Colorado Springs accessible CORA form.',
    'Pursuant to C.R.S. § 24-72-201 et seq.',
    'Response required within 3 working days per C.R.S. § 24-72-203.',
  ].join('\n');

  const subject = encodeURIComponent('CORA Records Request — ' + data['requester-name']);
  const bodyEnc = encodeURIComponent(body);
  return `mailto:${CORA_EMAIL}?subject=${subject}&body=${bodyEnc}`;
}

// ── MAILTO BUTTON ────────────────────────────────────────────────
document.getElementById('mailto-btn').addEventListener('click', function() {
  const data = collectData();
  window.location.href = buildMailtoHref(data);
});

// ── FORM SUBMIT ──────────────────────────────────────────────────
document.getElementById('cora-form').addEventListener('submit', async function(e) {
  e.preventDefault();
  if (!validate()) return;

  const data = collectData();

  // Honeypot check
  if (data.website) return; // bot — silently ignore

  const btn = document.getElementById('submit-btn');

  if (USE_AZURE) {
    // ── AZURE FUNCTION PATH ────────────────────────────────────────
    btn.disabled = true;
    btn.textContent = 'Submitting…';

    try {
      const res = await fetch(AZURE_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });

      const json = await res.json();

      if (json.success) {
        document.getElementById('cora-form').style.display = 'none';
        document.getElementById('mode-banner').style.display = 'none';
        const successPanel = document.getElementById('success-panel');
        document.getElementById('ref-display').textContent = json.reference || '—';
        successPanel.classList.add('visible');
        successPanel.focus();
      } else {
        btn.disabled = false;
        btn.textContent = 'Submit records request';
        // Fall back to mailto on Azure error
        fallbackToMailto(data, 'There was a problem with online submission. Please use email instead.');
      }

    } catch (err) {
      btn.disabled = false;
      btn.textContent = 'Submit records request';
      // Network error — fall back to mailto
      fallbackToMailto(data, 'Could not connect to the submission server. Please use email instead.');
    }

  } else {
    // ── MAILTO PATH ────────────────────────────────────────────────
    const href = buildMailtoHref(data);
    // Update the mailto button with current form data
    const mailtoBtn = document.getElementById('mailto-btn');
    mailtoBtn.style.display = 'inline-block';
    mailtoBtn.onclick = function() { window.location.href = href; };
    // Auto-trigger
    window.location.href = href;
    // Show confirmation note
    document.getElementById('mailto-note').textContent =
      'Your email client should have opened with the request pre-filled. ' +
      'Review the email and click Send. If it did not open, use the button above.';
  }
});

// ── MAILTO FALLBACK (called on Azure error) ──────────────────────
function fallbackToMailto(data, message) {
  const panel = document.getElementById('mailto-panel');
  const note  = document.getElementById('mailto-note');
  const btn   = document.getElementById('mailto-btn');
  const href  = buildMailtoHref(data);

  note.textContent = message;
  btn.style.display = 'inline-block';
  btn.onclick = function() { window.location.href = href; };

  panel.style.display = 'block';
  panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  panel.focus();
}

// ── LIVE VALIDATION on blur ──────────────────────────────────────
['record-description','requester-name','requester-address','requester-email']
  .forEach(id => {
    const el = document.getElementById(id);
    if (el) el.addEventListener('blur', validate);
  });

  // (No inline on* handlers detected — nothing to expose on window.)
})();
